1	'use client';
2	
3	import { AspectRatio, Image, type ImageProps, Skeleton } from '@mantine/core';
4	import { useCallback, useEffect, useRef, useState } from 'react';
5	
6	export interface Props extends Omit<ImageProps, 'onLoad' | 'onError' | 'src'> {
7	    /** Width / height ratio the space is reserved at, e.g. 1 for square, 3 / 2 for a flag. */
8	    ratio: number;
9	    alt: string;
10	    title?: string;
11	    /** Mantine types this as `any` for Next.js `StaticImageData` compatibility,
12	        but this component always renders a plain `<img>`, so a real API path
13	        is required here. */
14	    src: string;
15	    /** Called once the image has finished loading, or failed to. */
16	    onReady?: () => void;
17	}
18	
19	/**
20	 * Wraps Mantine's Image in a fixed-ratio box so its footprint is reserved
21	 * before the src has loaded, and shows a Skeleton over it until then —
22	 * avoiding the layout shift a bare `Image` causes while its bytes are still
23	 * in flight. `w` sizes the reserved box itself (defaulting to the full width
24	 * of its container); the image inside always fills that box.
25	 */
26	export const ImageWithPlaceholder = ({ ratio, radius, w = '100%', alt, onReady, ...imageProps }: Props) => {
27	    const [loaded, setLoaded] = useState(false);
28	
29	    // If this instance is reused for a different src (rather than remounted),
30	    // reset the skeleton for the new image's own loading lifecycle instead of
31	    // carrying over the previous image's "loaded" status.
32	    const [trackedSrc, setTrackedSrc] = useState(imageProps.src);
33	    if (imageProps.src !== trackedSrc) {
34	        setTrackedSrc(imageProps.src);
35	        setLoaded(false);
36	    }
37	
38	    const onReadyRef = useRef(onReady);
39	    useEffect(() => {
40	        onReadyRef.current = onReady;
41	    }, [onReady]);
42	
43	    // Guards against onReady firing twice for the same src — the mount-time
44	    // `.complete` check below and a subsequent `load`/`error` event can both
45	    // fire for a single image lifecycle.
46	    const readySrcRef = useRef<string | undefined>(undefined);
47	    const handleReady = useCallback(() => {
48	        setLoaded(true);
49	        if (readySrcRef.current !== imageProps.src) {
50	            readySrcRef.current = imageProps.src;
51	            onReadyRef.current?.();
52	        }
53	    }, [imageProps.src]);
54	
55	    // <img onLoad> never fires if the browser has already resolved the image
56	    // (e.g. served from cache) by the time React attaches the listener — a
57	    // well-known race that's especially likely on a fast local dev server.
58	    // A stable ref callback runs exactly once, right as the node mounts, so
59	    // check `.complete` there rather than waiting for an event that may have
60	    // already happened.
61	    const imgRef = useCallback((node: HTMLImageElement | null) => {
62	        if (node?.complete) handleReady();
63	    }, [handleReady]);
64	
65	    return (
66	        <AspectRatio ratio={ratio} w={w} pos="relative">
67	            <Skeleton
68	                visible={!loaded}
69	                radius={radius}
70	                pos="absolute"
71	                inset={0}
72	                aria-hidden="true"
73	            />
74	            <Image
75	                {...imageProps}
76	                ref={imgRef}
77	                alt={alt}
78	                radius={radius}
79	                onLoad={handleReady}
80	                onError={handleReady}
81	                style={{ opacity: loaded ? 1 : 0, transition: 'opacity 150ms ease' }}
82	            />
83	        </AspectRatio>
84	    );
85	};
