3	import { Box, Paper } from '@mantine/core';
4	import type { TableName } from 'prisma/generated/browser';
5	import type { PlayerRecordType } from 'prisma/zod/schemas/models/PlayerRecord.schema';
6	import { useState } from 'react';
7	
8	import { PlayerClubs } from '@/components/PlayerClubs/PlayerClubs';
9	import { PlayerCountries } from '@/components/PlayerCountries/PlayerCountries';
10	import { PlayerMugshot } from '@/components/PlayerMugshot/PlayerMugshot';
11	import { PlayerTrophies } from '@/components/PlayerTrophies/PlayerTrophies';
12	import { PlayerDisplayType } from '@/services/Player';
13	import { ClubSupporterDataType, CountrySupporterDataType } from '@/types';
14	
15	import classes from './PlayerCard.module.css';
16	
17	export interface Props {
18	    player: PlayerDisplayType;
19	    clubs: ClubSupporterDataType[];
20	    countries: CountrySupporterDataType[];
21	    trophies: Map<TableName, PlayerRecordType[]>;
22	}
23	
24	export const PlayerCard = ({ player, clubs, countries, trophies }: Props) => {
25	    return (
26	        <Paper shadow="xs" p="sm" miw="280px" h="100%" withBorder>
27	            {/* Keyed by player.id: if this PlayerCard instance is reused for a
28	                different player (e.g. prev/next navigation re-rendering in
29	                place rather than remounting), React discards and recreates
30	                this subtree from scratch, so its "is the mugshot ready" state
31	                — and the mugshot's own internal loaded state — start fresh
32	                rather than instantly showing the previous player's overlays. */}
33	            <PlayerCardImage
34	                key={player.id}
35	                player={player}
36	                clubs={clubs}
37	                countries={countries}
38	                trophies={trophies}
39	            />
40	        </Paper>
41	    );
42	};
43	
44	const PlayerCardImage = ({ player, clubs, countries, trophies }: Props) => {
45	    // The trophies/clubs/countries overlays don't fetch anything of their own
46	    // that's worth a skeleton for — they simply reveal together once the
47	    // mugshot (whose own AspectRatio already reserves the card's footprint)
48	    // has finished loading, rather than each popping in independently.
49	    const [mugshotReady, setMugshotReady] = useState(false);
50	    // Fading via opacity alone would still leave these hit-testable, exposed
51	    // to assistive tech, and keyboard-focusable while "hidden". `inert` is
52	    // the one attribute that covers all three (pointer, a11y tree, and
53	    // focus) for any content that ends up inside these overlays, now or
54	    // later; `pointerEvents`/`aria-hidden` stay on as a fallback for browsers
55	    // that don't yet support `inert`.
56	    const overlayStyle = {
57	        opacity: mugshotReady ? 1 : 0,
58	        pointerEvents: mugshotReady ? 'auto' : 'none',
59	        transition: 'opacity 150ms ease',
60	    } as const;
61	
62	    return (
63	        <Box w="100%" pos="relative" className={classes.imageContainer}>
64	            <PlayerMugshot player={player} onReady={() => setMugshotReady(true)} />
65	            <Box
66	                className={classes.trophies}
67	                left="0.5em"
68	                top="0.5em"
69	                style={overlayStyle}
70	                aria-hidden={!mugshotReady}
71	                inert={!mugshotReady}
72	            >
73	                <PlayerTrophies trophies={trophies} />
74	            </Box>
75	            <Box
76	                className={classes.badges}
77	                right="0.5em"
78	                bottom="0.5em"
79	                style={overlayStyle}
80	                aria-hidden={!mugshotReady}
81	                inert={!mugshotReady}
82	            >
83	                <PlayerClubs clubs={clubs} />
84	            </Box>
85	            <Box
86	                className={classes.badges}
87	                left="0.5em"
88	                bottom="0.5em"
89	                style={overlayStyle}
90	                aria-hidden={!mugshotReady}
91	                inert={!mugshotReady}
92	            >
93	                <PlayerCountries countries={countries} />
94	            </Box>
95	        </Box>
96	    );
97	};
