18	export const GameDaySummary = ({
19	    gameDay,
20	    prevGameDay,
21	    nextGameDay,
22	    teamA,
23	    teamB,
24	}: Props) => {
25	    const winner = getGameWinnersFromTeams(teamA, teamB);
26	    const noGame = gameDay.game ? `` : `No game`;
27	    const comment = gameDay.comment ? `(${gameDay.comment})` : ``;
28	    const maxTeamSize = Math.max(teamA.length, teamB.length);
29	    const navSlotWidth = '2rem';
30	
31	    return (
32	        <Flex direction="column" gap="sm">
33	            <Group justify="space-between" gap="xs">
34	                <Box w={navSlotWidth} ta="center">
35	                    {prevGameDay ?
36	                        <GameDayLink gameDay={prevGameDay} format="left-arrow" /> :
37	                        <Box data-testid="game-day-prev-placeholder" aria-hidden="true" w={navSlotWidth} />}
38	                </Box>
39	                <Title order={1}>{formatDate(gameDay.date)}</Title>
40	                <Box w={navSlotWidth} ta="center">
41	                    {nextGameDay ?
42	                        <GameDayLink gameDay={nextGameDay} format="right-arrow" /> :
43	                        <Box data-testid="game-day-next-placeholder" aria-hidden="true" w={navSlotWidth} />}
44	                </Box>
45	            </Group>
46	            {(
47	                <Text ta="center">
48	                    {[noGame, comment].join(' ').trim()}
49	                </Text>
50	            )}
51	            {gameDay.game ?
52	                (<SimpleGrid cols={{ base: 2, lg: 1 }} spacing="md">
53	                    <Team
54	                        team={teamA}
55	                        teamName="A"
56	                        maxTeamSize={maxTeamSize}
57	                        result={getTeamResultState('A', winner)}
58	                        hasBibs={gameDay.bibs === 'A'}
59	                    />
60	                    <Team
61	                        team={teamB}
62	                        teamName="B"
63	                        maxTeamSize={maxTeamSize}
64	                        result={getTeamResultState('B', winner)}
65	                        hasBibs={gameDay.bibs === 'B'}
66	                    />
67	                </SimpleGrid>) : null}
68	        </Flex>
69	    );
70	};
