82	const parseCookies = (cookieHeader: string | null): Record<string, string> => {
83	    if (!cookieHeader) return {};
84	    return cookieHeader.split(';').reduce<Record<string, string>>((acc, cookie) => {
85	        const trimmed = cookie.trim();
86	        if (!trimmed) return acc;
87	        const [name, ...rest] = trimmed.split('=');
88	        if (!name) return acc;
89	        acc[name] = decodeURIComponent(rest.join('='));
90	        return acc;
91	    }, {});
92	};
93	
94	const resolveMockAuth = (cookieHeader: string | null) => {
95	    const cookies = parseCookies(cookieHeader);
96	    const role = cookies[MOCK_AUTH_COOKIE] as MockAuthState | undefined;
97	    const userRaw = cookies[MOCK_AUTH_USER_COOKIE];
98	    let userOverride: MockAuthUser | null = null;
99	    if (userRaw) {
100	        try {
101	            userOverride = JSON.parse(userRaw) as MockAuthUser;
102	        } catch {
103	            userOverride = null;
104	        }
105	    }
106	
107	    const effectiveRole = role === 'admin' || role === 'user' ? role : 'none';
108	    if (effectiveRole === 'none') {
109	        return { role: 'none' as const, user: null };
110	    }
111	
112	    const baseUser = defaultMockUsers[effectiveRole];
113	    const user = {
114	        ...baseUser,
115	        ...userOverride,
116	        role: effectiveRole,
117	    };
118	    return { role: effectiveRole, user };
119	};
