121	const mockAuthDecorator: Decorator = (Story, context) => {
122	    useEffect(() => {
123	        if (typeof document === 'undefined') return;
124	        const { role = 'none', user } = (context.parameters?.mockAuth ?? {}) as {
125	            role?: MockAuthState;
126	            user?: MockAuthUser;
127	        };
128	
129	        if (role === 'none') {
130	            document.cookie = `${MOCK_AUTH_COOKIE}=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
131	            document.cookie = `${MOCK_AUTH_USER_COOKIE}=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
132	            return;
133	        }
134	
135	        document.cookie = `${MOCK_AUTH_COOKIE}=${encodeURIComponent(role)}; path=/`;
136	        if (user) {
137	            document.cookie = `${MOCK_AUTH_USER_COOKIE}=${encodeURIComponent(JSON.stringify(user))}; path=/`;
138	        } else {
139	            document.cookie = `${MOCK_AUTH_USER_COOKIE}=; path=/; expires=Thu, 01 Jan 1970 00:00:00 GMT`;
140	        }
141	    }, [context.parameters?.mockAuth]);
142	
