1	import { Flex } from '@mantine/core';
2	import type { Metadata } from 'next';
3	import { notFound, permanentRedirect } from 'next/navigation';
4	import { cache } from 'react';
5	import z from 'zod';
6	
7	import { setGameResult } from '@/actions/setGameResult';
8	import { AutoRefresh } from '@/components/AutoRefresh/AutoRefresh';
9	import { GameDaySummary } from '@/components/GameDaySummary/GameDaySummary';
10	import { GameResultForm } from '@/components/GameResultForm/GameResultForm';
11	import { getUserRole } from '@/lib/auth.server';
12	import { formatDate } from '@/lib/dates';
13	import { getGameWinnersFromTeams } from '@/lib/gameResult';
14	import gameDayService from '@/services/GameDay';
15	import outcomeService from '@/services/Outcome';
16	import { FootyChannel } from '@/types/FootyChannel';
17	
18	interface PageProps {
19	    params: Promise<{ id: string }>;
20	}
21	
22	/**
23	 * Unpacks and validates route parameters for the game detail page.
24	 *
25	 * Validates the `id` parameter as a positive integer, retrieves the
26	 * corresponding game day, and handles redirects to the canonical URL if needed.
27	 *
28	 * @param params - The route parameters object containing the `id` property
29	 * @returns A promise that resolves to an object containing the validated
30	 * `gameDay`
31	 * @throws Calls `notFound()` if the game day cannot be found or the ID is
32	 * invalid
33	 * @throws Calls `permanentRedirect()` if the current URL doesn't match the
34	 * canonical URL
35	 */
36	const unpackParams = cache(async (
37	    params: PageProps['params'],
38	) => {
39	    const { id } = await params;
40	
41	    const gameDayId = z.coerce.number().int().min(1).safeParse(id);
42	    const gameDay = gameDayId.success ? await gameDayService.get(gameDayId.data) : undefined;
43	    if (!gameDay) notFound();
44	
45	    const canonicalUrl = `/footy/game/${gameDay.id}`;
46	    const currentUrl = `/footy/game/${id}`;
47	    if (currentUrl !== canonicalUrl) permanentRedirect(canonicalUrl);
48	
49	    return { gameDay };
50	});
51	
52	/**
53	 * Generates metadata for a game page.
54	 * @param props - The page props containing route parameters
55	 * @param props.params - Route parameters including the game ID
56	 * @returns A promise that resolves to metadata with the game title and date
57	 */
58	export async function generateMetadata(props: PageProps): Promise<Metadata> {
59	    const { gameDay } = await unpackParams(props.params);
60	
61	    return {
62	        title: formatDate(gameDay.date),
63	    };
64	}
65	
66	/**
67	 * Displays a football game day page with game details, team information, and
68	 * navigation.
69	 *
70	 * This is an async Server Component that fetches game data, determines user
71	 * role, and renders game results, player teams, and administrative controls
72	 * based on permissions.
73	 *
74	 * @component
75	 * @param {PageProps} props - The page component props
76	 * @param {object} props.params - Route parameters containing the game ID
77	 * @returns {Promise<React.ReactElement>} A flex container with game navigation,
78	 * admin controls, and game summary
79	 *
80	 * @remarks
81	 * - Fetches previous and next game days for navigation
82	 * - Retrieves team rosters (up to 10 players per team) for the current game day
83	 * - Calculates game winners from team data
84	 * - Only displays the GameResultForm if the user has an 'admin' role
85	 * - Navigation links (Previous/Next) are conditionally rendered based on data
86	 *   availability
87	 *
88	 * @requires getUserRole - To determine user permissions
89	 * @requires unpackParams - To extract gameDay from route params
90	 * @requires gameDayService.getPrevious - To fetch previous game
91	 * @requires gameDayService.getNext - To fetch next game
92	 * @requires outcomeService.getTeamPlayersByGameDay - To fetch team rosters
93	 * @requires getGameWinnersFromTeams - To calculate match winners
94	 */
95	const GamePage = async (props: PageProps) => {
96	    const { gameDay } = await unpackParams(props.params);
97	    const [role, prevGameDay, nextGameDay, teamA, teamB] = await Promise.all([
98	        getUserRole(),
99	        gameDayService.getPrevious(gameDay.id),
100	        gameDayService.getNext(gameDay.id),
101	        outcomeService.getTeamPlayersByGameDay(gameDay.id, 'A', 10),
102	        outcomeService.getTeamPlayersByGameDay(gameDay.id, 'B', 10),
103	    ]);
104	    const winners = getGameWinnersFromTeams(teamA, teamB);
105	
106	    return (
107	        <Flex w="100%" direction="column" gap="md">
108	            <AutoRefresh channels={[FootyChannel.Games, FootyChannel.Results]} />
109	            <GameDaySummary
110	                gameDay={gameDay}
111	                prevGameDay={prevGameDay}
112	                nextGameDay={nextGameDay}
113	                teamA={teamA}
114	                teamB={teamB}
115	            />
116	            {role === 'admin' && !!gameDay.game && (
117	                <GameResultForm
118	                    gameDayId={gameDay.id}
119	                    bibs={gameDay.bibs ?? null}
120	                    winners={winners}
121	                    setGameResult={setGameResult}
122	                />
123	            )}
124	        </Flex>
125	    );
126	};
127	
128	export default GamePage;
